SELECT COUNT(*) FROM (
    SELECT T.* FROM (

    ) T


            (CONVERTTOUNSIGN(UPPER(T.EMP_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{keyword, jdbcType=VARCHAR})) || '%'
            OR T.EMP_CODE LIKE '%' || #{keyword, jdbcType=VARCHAR} || '%')


)

SELECT * FROM (
    SELECT A.*, ROWNUM AS RN FROM (
        SELECT * FROM (
            SELECT T.* FROM (

            ) T


                    (CONVERTTOUNSIGN(UPPER(T.EMP_NAME)) LIKE '%' || CONVERTTOUNSIGN(UPPER(#{keyword, jdbcType=VARCHAR})) || '%'
                    OR T.EMP_CODE LIKE '%' || #{keyword, jdbcType=VARCHAR} || '%')


        ) ORDER BY CREATE_DATE DESC, APPLY_NO DESC
    ) A WHERE ROWNUM <= #{start, jdbcType=NUMERIC} + #{length, jdbcType=NUMERIC}
) WHERE RN > #{start, jdbcType=NUMERIC}

