UPDATE HR_PERSONAL_INFO_APPLY
SET ACTIVITY    = #{activity, jdbcType=NUMERIC},
    UPDATE_DATE = SYSDATE,
    UPDATED_BY  = #{adminID,  jdbcType=VARCHAR},
    UPDATED_IP  = #{adminIP,  jdbcType=VARCHAR}
WHERE PERSON_NO = #{applyNo, jdbcType=VARCHAR}

